     1→import React, { useEffect, useState } from 'react';
     2→import {
     3→  View,
     4→  Text,
     5→  TouchableOpacity,
     6→  StyleSheet,
     7→  SafeAreaView,
     8→  Alert,
     9→} from 'react-native';
    10→import { useRouter } from 'expo-router';
    11→import AsyncStorage from '@react-native-async-storage/async-storage';
    12→import { useAuth } from '@/context/AuthContext';
    13→import { ECR_R_QUESTIONS, LIKERT_LABELS } from '@/utils/questions';
    14→import { calculateECRRScores } from '@/utils/scoring';
    15→import { supabase } from '@/services/supabase';
    16→import { Colors, Spacing, FontSizes, ButtonSizes } from '@/constants/theme';
    17→
    18→const ASSESSMENT_PROGRESS_KEY = 'ecr_r_progress';
    19→const TOTAL_QUESTIONS = 36;
    20→
    21→export default function AssessmentScreen() {
    22→  const { user } = useAuth();
    23→  const router = useRouter();
    24→  const [currentIndex, setCurrentIndex] = useState(0);
    25→  const [responses, setResponses] = useState<(number | null)[]>(
    26→    new Array(TOTAL_QUESTIONS).fill(null)
    27→  );
    28→  const [submitting, setSubmitting] = useState(false);
    29→
    30→  // Load saved progress on mount
    31→  useEffect(() => {
    32→    loadProgress();
    33→  }, []);
    34→
    35→  const loadProgress = async () => {
    36→    try {
    37→      const saved = await AsyncStorage.getItem(ASSESSMENT_PROGRESS_KEY);
    38→      if (saved) {
    39→        const data = JSON.parse(saved);
    40→        setResponses(data.responses);
    41→        setCurrentIndex(data.currentIndex);
    42→      }
    43→    } catch {
    44→      // Start fresh
    45→    }
    46→  };
    47→
    48→  const saveProgress = async (
    49→    newResponses: (number | null)[],
    50→    newIndex: number
    51→  ) => {
    52→    try {
    53→      await AsyncStorage.setItem(
    54→        ASSESSMENT_PROGRESS_KEY,
    55→        JSON.stringify({ responses: newResponses, currentIndex: newIndex })
    56→      );
    57→    } catch {
    58→      // Silent fail — not critical
    59→    }
    60→  };
    61→
    62→  const handleSelect = (value: number) => {
    63→    const newResponses = [...responses];
    64→    newResponses[currentIndex] = value;
    65→    setResponses(newResponses);
    66→    saveProgress(newResponses, currentIndex);
    67→  };
    68→
    69→  const handleNext = () => {
    70→    if (currentIndex < TOTAL_QUESTIONS - 1) {
    71→      const nextIndex = currentIndex + 1;
    72→      setCurrentIndex(nextIndex);
    73→      saveProgress(responses, nextIndex);
    74→    }
    75→  };
    76→
    77→  const handlePrevious = () => {
    78→    if (currentIndex > 0) {
    79→      const prevIndex = currentIndex - 1;
    80→      setCurrentIndex(prevIndex);
    81→      saveProgress(responses, prevIndex);
    82→    }
    83→  };
    84→
    85→  const handleSubmit = async () => {
    86→    // Validate all answered
    87→    const unanswered = responses.findIndex((r) => r === null);
    88→    if (unanswered !== -1) {
    89→      Alert.alert(
    90→        'Incomplete',
    91→        `Please answer all questions. Question ${unanswered + 1} is unanswered.`,
    92→        [
    93→          {
    94→            text: 'Go to question',
    95→            onPress: () => setCurrentIndex(unanswered),
    96→          },
    97→        ]
    98→      );
    99→      return;
   100→    }
   101→
   102→    setSubmitting(true);
   103→
   104→    try {
   105→      const validResponses = responses as number[];
   106→      const scores = calculateECRRScores(validResponses);
   107→
   108→      // Save to Supabase
   109→      const { error } = await supabase.from('ecr_r_assessments').insert({
   110→        user_id: user!.id,
   111→        responses: validResponses,
   112→        anxiety_score: scores.anxietyScore,
   113→        avoidance_score: scores.avoidanceScore,
   114→        attachment_style: scores.attachmentStyle,
   115→        completed_at: new Date().toISOString(),
   116→      });
   117→
   118→      if (error) {
   119→        Alert.alert('Error', 'Failed to save results. Please try again.');
   120→        setSubmitting(false);
   121→        return;
   122→      }
   123→
   124→      // Clear saved progress
   125→      await AsyncStorage.removeItem(ASSESSMENT_PROGRESS_KEY);
   126→
   127→      // Navigate to results
   128→      router.replace({
   129→        pathname: '/(app)/results',
   130→        params: {
   131→          anxietyScore: scores.anxietyScore.toString(),
   132→          avoidanceScore: scores.avoidanceScore.toString(),
   133→          attachmentStyle: scores.attachmentStyle,
   134→        },
   135→      });
   136→    } catch (e) {
   137→      Alert.alert('Error', 'Something went wrong. Please try again.');
   138→      setSubmitting(false);
   139→    }
   140→  };
   141→
   142→  const question = ECR_R_QUESTIONS[currentIndex];
   143→  const progress = ((currentIndex + 1) / TOTAL_QUESTIONS) * 100;
   144→  const isLastQuestion = currentIndex === TOTAL_QUESTIONS - 1;
   145→  const currentAnswer = responses[currentIndex];
   146→
   147→  return (
   148→    <SafeAreaView style={styles.container}>
   149→      <View style={styles.content}>
   150→        {/* Progress */}
   151→        <View style={styles.progressSection}>
   152→          <Text style={styles.progressText}>
   153→            Question {currentIndex + 1} of {TOTAL_QUESTIONS}
   154→          </Text>
   155→          <View style={styles.progressBarBg}>
   156→            <View style={[styles.progressBarFill, { width: `${progress}%` }]} />
   157→          </View>
   158→          <Text style={styles.percentText}>{Math.round(progress)}% complete</Text>
   159→        </View>
   160→
   161→        {/* Question */}
   162→        <View style={styles.questionSection}>
   163→          <Text style={styles.questionText}>"{question.text}"</Text>
   164→        </View>
   165→
   166→        {/* Likert Scale */}
   167→        <View style={styles.likertSection}>
   168→          {LIKERT_LABELS.map((item) => (
   169→            <TouchableOpacity
   170→              key={item.value}
   171→              style={[
   172→                styles.likertOption,
   173→                currentAnswer === item.value && styles.likertOptionSelected,
   174→              ]}
   175→              onPress={() => handleSelect(item.value)}
   176→            >
   177→              <View
   178→                style={[
   179→                  styles.radio,
   180→                  currentAnswer === item.value && styles.radioSelected,
   181→                ]}
   182→              >
   183→                {currentAnswer === item.value && (
   184→                  <View style={styles.radioInner} />
   185→                )}
   186→              </View>
   187→              <Text
   188→                style={[
   189→                  styles.likertLabel,
   190→                  currentAnswer === item.value && styles.likertLabelSelected,
   191→                ]}
   192→              >
   193→                {item.value} — {item.label}
   194→              </Text>
   195→            </TouchableOpacity>
   196→          ))}
   197→        </View>
   198→
   199→        {/* Navigation */}
   200→        <View style={styles.navSection}>
   201→          <TouchableOpacity
   202→            style={[styles.navButton, currentIndex === 0 && styles.navButtonDisabled]}
   203→            onPress={handlePrevious}
   204→            disabled={currentIndex === 0}
   205→          >
   206→            <Text
   207→              style={[
   208→                styles.navButtonText,
   209→                currentIndex === 0 && styles.navButtonTextDisabled,
   210→              ]}
   211→            >
   212→              Previous
   213→            </Text>
   214→          </TouchableOpacity>
   215→
   216→          {isLastQuestion ? (
   217→            <TouchableOpacity
   218→              style={[
   219→                styles.submitButton,
   220→                (currentAnswer === null || submitting) && styles.navButtonDisabled,
   221→              ]}
   222→              onPress={handleSubmit}
   223→              disabled={currentAnswer === null || submitting}
   224→            >
   225→              <Text style={styles.submitButtonText}>
   226→                {submitting ? 'Submitting...' : 'See Results'}
   227→              </Text>
   228→            </TouchableOpacity>
   229→          ) : (
   230→            <TouchableOpacity
   231→              style={[
   232→                styles.navButton,
   233→                styles.navButtonPrimary,
   234→                currentAnswer === null && styles.navButtonDisabled,
   235→              ]}
   236→              onPress={handleNext}
   237→              disabled={currentAnswer === null}
   238→            >
   239→              <Text style={styles.navButtonPrimaryText}>Next</Text>
   240→            </TouchableOpacity>
   241→          )}
   242→        </View>
   243→      </View>
   244→    </SafeAreaView>
   245→  );
   246→}
