     1→import { createClient } from '@supabase/supabase-js';
     2→import { Platform } from 'react-native';
     3→
     4→const supabaseUrl = process.env.EXPO_PUBLIC_SUPABASE_URL!;
     5→const supabaseAnonKey = process.env.EXPO_PUBLIC_SUPABASE_ANON_KEY!;
     6→
     7→// AsyncStorage doesn't work in SSR/Node — use a safe wrapper
     8→const createStorage = () => {
     9→  // On web SSR (Node), there's no window — use in-memory fallback
    10→  if (Platform.OS === 'web' && typeof window === 'undefined') {
    11→    const memoryStore: Record<string, string> = {};
    12→    return {
    13→      getItem: (key: string) => Promise.resolve(memoryStore[key] ?? null),
    14→      setItem: (key: string, value: string) => {
    15→        memoryStore[key] = value;
    16→        return Promise.resolve();
    17→      },
    18→      removeItem: (key: string) => {
    19→        delete memoryStore[key];
    20→        return Promise.resolve();
    21→      },
    22→    };
    23→  }
    24→
    25→  // On web client, use localStorage
    26→  if (Platform.OS === 'web') {
    27→    return {
    28→      getItem: (key: string) => Promise.resolve(localStorage.getItem(key)),
    29→      setItem: (key: string, value: string) => {
    30→        localStorage.setItem(key, value);
    31→        return Promise.resolve();
    32→      },
    33→      removeItem: (key: string) => {
    34→        localStorage.removeItem(key);
    35→        return Promise.resolve();
    36→      },
    37→    };
    38→  }
    39→
    40→  // On native, use AsyncStorage (lazy import to avoid SSR crash)
    41→  const AsyncStorage =
    42→    require('@react-native-async-storage/async-storage').default;
    43→  return AsyncStorage;
    44→};
    45→
    46→export const supabase = createClient(supabaseUrl, supabaseAnonKey, {
    47→  auth: {
    48→    storage: createStorage(),
    49→    autoRefreshToken: true,
    50→    persistSession: true,
    51→    detectSessionInUrl: false,
    52→  },
    53→});
