     1→import { AttachmentStyle, ECRRScores } from '@/types';
     2→
     3→/**
     4→ * Reverse-scored item indices (0-indexed).
     5→ * 1-indexed items 20, 21, 30, 33, 34, 35 → 0-indexed 19, 20, 29, 32, 33, 34
     6→ */
     7→const REVERSE_ITEMS_0_INDEXED = [19, 20, 29, 32, 33, 34];
     8→
     9→/**
    10→ * Calculate ECR-R scores from 36 responses.
    11→ *
    12→ * @param responses Array of 36 integers (1-7)
    13→ * @returns { anxietyScore, avoidanceScore, attachmentStyle }
    14→ */
    15→export function calculateECRRScores(responses: number[]): ECRRScores {
    16→  if (responses.length !== 36) {
    17→    throw new Error('Responses must be an array of 36 integers');
    18→  }
    19→  if (!responses.every(r => Number.isInteger(r) && r >= 1 && r <= 7)) {
    20→    throw new Error('All responses must be integers between 1 and 7');
    21→  }
    22→
    23→  // Copy to avoid mutation
    24→  const adjusted = [...responses];
    25→
    26→  // Step 1: Reverse-score specific items
    27→  for (const idx of REVERSE_ITEMS_0_INDEXED) {
    28→    adjusted[idx] = 8 - adjusted[idx];
    29→  }
    30→
    31→  // Step 2: Anxiety = mean of items 1-18 (indices 0-17)
    32→  const anxietySum = adjusted.slice(0, 18).reduce((sum, val) => sum + val, 0);
    33→  const anxietyScore = parseFloat((anxietySum / 18).toFixed(2));
    34→
    35→  // Step 3: Avoidance = mean of items 19-36 (indices 18-35)
    36→  const avoidanceSum = adjusted.slice(18, 36).reduce((sum, val) => sum + val, 0);
    37→  const avoidanceScore = parseFloat((avoidanceSum / 18).toFixed(2));
    38→
    39→  // Step 4: Determine quadrant
    40→  const attachmentStyle = getAttachmentStyle(anxietyScore, avoidanceScore);
    41→
    42→  return { anxietyScore, avoidanceScore, attachmentStyle };
    43→}
    44→
    45→function getAttachmentStyle(anxiety: number, avoidance: number): AttachmentStyle {
    46→  const anxietyHigh = anxiety >= 4.0;
    47→  const avoidanceHigh = avoidance >= 4.0;
    48→
    49→  if (!anxietyHigh && !avoidanceHigh) return 'secure';
    50→  if (anxietyHigh && !avoidanceHigh) return 'anxious-preoccupied';
    51→  if (!anxietyHigh && avoidanceHigh) return 'dismissive-avoidant';
    52→  return 'fearful-avoidant';
    53→}
