     1→import React, { createContext, useContext, useEffect, useState } from 'react';
     2→import { Session, User } from '@supabase/supabase-js';
     3→import { supabase } from '@/services/supabase';
     4→
     5→interface AuthContextType {
     6→  session: Session | null;
     7→  user: User | null;
     8→  loading: boolean;
     9→  signUp: (email: string, password: string) => Promise<{ error: string | null }>;
    10→  signIn: (email: string, password: string) => Promise<{ error: string | null }>;
    11→  signOut: () => Promise<void>;
    12→}
    13→
    14→const AuthContext = createContext<AuthContextType | undefined>(undefined);
    15→
    16→export function AuthProvider({ children }: { children: React.ReactNode }) {
    17→  const [session, setSession] = useState<Session | null>(null);
    18→  const [loading, setLoading] = useState(true);
    19→
    20→  useEffect(() => {
    21→    // Get initial session
    22→    supabase.auth.getSession().then(({ data: { session } }) => {
    23→      setSession(session);
    24→      setLoading(false);
    25→    });
    26→
    27→    // Listen for auth changes
    28→    const { data: { subscription } } = supabase.auth.onAuthStateChange(
    29→      (_event, session) => {
    30→        setSession(session);
    31→      }
    32→    );
    33→
    34→    return () => subscription.unsubscribe();
    35→  }, []);
    36→
    37→  const signUp = async (email: string, password: string) => {
    38→    const { data, error } = await supabase.auth.signUp({ email, password });
    39→    if (error) return { error: error.message };
    40→    // Explicitly set session if returned (when email confirm is OFF)
    41→    if (data.session) {
    42→      setSession(data.session);
    43→    }
    44→    return { error: null };
    45→  };
    46→
    47→  const signIn = async (email: string, password: string) => {
    48→    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    49→    if (error) return { error: error.message };
    50→    // Explicitly set session
    51→    if (data.session) {
    52→      setSession(data.session);
    53→    }
    54→    return { error: null };
    55→  };
    56→
    57→  const signOut = async () => {
    58→    await supabase.auth.signOut();
    59→    setSession(null);
    60→  };
    61→
    62→  return (
    63→    <AuthContext.Provider
    64→      value={{
    65→        session,
    66→        user: session?.user ?? null,
    67→        loading,
    68→        signUp,
    69→        signIn,
    70→        signOut,
    71→      }}
    72→    >
    73→      {children}
    74→    </AuthContext.Provider>
    75→  );
    76→}
    77→
    78→export function useAuth() {
    79→  const context = useContext(AuthContext);
    80→  if (context === undefined) {
    81→    throw new Error('useAuth must be used within an AuthProvider');
    82→  }
    83→  return context;
    84→}
