   428→```javascript
   429→function analyzeAttachmentProtection(profile, patterns) {
   430→  const { attachment, conflictStyle, differentiation, values } = profile;
   431→  
   432→  // Determine primary attachment narrative
   433→  let attachmentNarrative;
   434→  let protectiveStrategy;
   435→  let primaryEmotion;
   436→  let secondaryEmotion;
   437→  let longing;
   438→  
   439→  if (attachment.attachmentStyle === 'secure') {
   440→    attachmentNarrative = 'secure_earned_or_natural';
   441→    protectiveStrategy = 'direct_communication';
   442→    primaryEmotion = 'trust';
   443→    secondaryEmotion = 'openness';
   444→    longing = 'continued_connection';
   445→  } else if (attachment.attachmentStyle === 'anxious-preoccupied') {
   446→    attachmentNarrative = 'learned_love_is_precarious';
   447→    protectiveStrategy = 'pursue_seek_reassurance';
   448→    primaryEmotion = 'fear_of_abandonment';
   449→    secondaryEmotion = 'anger_or_criticism';
   450→    longing = 'reassurance_that_they_matter';
   451→  } else if (attachment.attachmentStyle === 'dismissive-avoidant') {
   452→    attachmentNarrative = 'learned_self_reliance_is_safer';
   453→    protectiveStrategy = 'withdraw_minimize_needs';
   454→    primaryEmotion = 'fear_of_engulfment';
   455→    secondaryEmotion = 'numbness_or_dismissiveness';
   456→    longing = 'acceptance_without_demands';
   457→  } else {
   458→    attachmentNarrative = 'learned_love_is_both_needed_and_dangerous';
   459→    protectiveStrategy = 'approach_then_withdraw';
   460→    primaryEmotion = 'fear_of_both_abandonment_and_engulfment';
   461→    secondaryEmotion = 'confusion_or_dysregulation';
   462→    longing = 'safe_connection_that_wont_hurt';
   463→  }
   464→  
   465→  // Calculate A.R.E. profile (Accessible, Responsive, Engaged)
   466→  const areProfile = {
   467→    accessible: calculateAccessibility(attachment, differentiation),
   468→    responsive: calculateResponsiveness(profile),
   469→    engaged: calculateEngagement(profile)
   470→  };
   471→  
   472→  // Identify attachment triggers
   473→  const triggers = identifyAttachmentTriggers(attachment, patterns);
   474→  
   475→  return {
   476→    attachmentStyle: attachment.attachmentStyle,
   477→    anxietyScore: attachment.anxietyScore,
   478→    avoidanceScore: attachment.avoidanceScore,
   479→    narrative: attachmentNarrative,
   480→    protectiveStrategy: protectiveStrategy,
   481→    emotionalStructure: {
   482→      primary: primaryEmotion,
   483→      secondary: secondaryEmotion,
   484→      longing: longing
   485→    },
   486→    areProfile: areProfile,
   487→    triggers: triggers,
   488→    relatedPatterns: patterns.patterns.filter(p => 
   489→      p.id.includes('attachment') || 
   490→      p.id.includes('anxious') || 
   491→      p.id.includes('avoidant')
   492→    )
   493→  };
   494→}
   495→
   496→function calculateAccessibility(attachment, differentiation) {
   497→  // Accessibility = how easy to reach emotionally
   498→  // Low avoidance + low cutoff = high accessibility
   499→  const avoidanceContrib = (7 - attachment.avoidanceScore) / 6; // 0-1, higher is more accessible
   500→  const cutoffContrib = differentiation.subscaleNormalized.emotionalCutoff / 100;
   501→  return Math.round(((avoidanceContrib * 0.6) + (cutoffContrib * 0.4)) * 100);
   502→}
   503→
   504→function calculateResponsiveness(profile) {
   505→  // Responsiveness = how well they respond to partner's needs
   506→  // High empathy + high altruism + low self-focus
   507→  const empathy = profile.emotionalIntelligence.subscaleNormalized.perception;
   508→  const altruism = profile.personality.facetPercentiles.A3_Altruism || 50;
   509→  return Math.round((empathy * 0.5 + altruism * 0.5));
   510→}
   511→
   512→function calculateEngagement(profile) {
   513→  // Engagement = presence and attention in connection
   514→  // Low avoidance + high extraversion friendliness facet + low cutoff
   515→  const avoidanceContrib = (7 - profile.attachment.avoidanceScore) / 6 * 100;
   516→  const friendliness = profile.personality.facetPercentiles.E1_Friendliness || 50;
   517→  return Math.round((avoidanceContrib * 0.5 + friendliness * 0.5));
   518→}
   519→
   520→function identifyAttachmentTriggers(attachment, patterns) {
   521→  const triggers = [];
   522→  
   523→  if (attachment.anxietyScore > 4.0) {
   524→    triggers.push({
   525→      trigger: 'partner_unavailability',
   526→      description: 'Partner being busy, distracted, or emotionally distant',
   527→      response: 'Anxiety rises, may pursue or seek reassurance'
   528→    });
   529→    triggers.push({
   530→      trigger: 'ambiguous_communication',
   531→      description: 'Unclear messages, delayed responses, vague plans',
   532→      response: 'Mind fills in negative interpretations'
   533→    });
   534→    triggers.push({
   535→      trigger: 'perceived_rejection',
   536→      description: 'Criticism, disinterest, attention to others',
   537→      response: 'Activation, protest behaviors, or collapse'
   538→    });
   539→  }
   540→  
   541→  if (attachment.avoidanceScore > 4.0) {
   542→    triggers.push({
   543→      trigger: 'demands_for_closeness',
   544→      description: 'Partner wanting more time, more talk, more intimacy',
   545→      response: 'Feels engulfed, withdraws, needs space'
   546→    });
   547→    triggers.push({
   548→      trigger: 'emotional_intensity',
   549→      description: 'Partner expressing strong emotions or needs',
   550→      response: 'Shuts down, goes logical, or distances'
   551→    });
   552→    triggers.push({
   553→      trigger: 'conflict_escalation',
   554→      description: 'Arguments becoming heated or repetitive',
   555→      response: 'Stonewalls or exits to self-regulate'
   556→    });
   557→  }
   558→  
   559→  return triggers;
   560→}
