   693→  
   694→  const reactivity = profile.differentiation.subscaleNormalized.emotionalReactivity;
   695→  const iPosition = profile.differentiation.subscaleNormalized.iPosition;
   696→  const regulation = profile.emotionalIntelligence.subscaleNormalized.managingOwn;
   697→  const neuroticism = 100 - profile.personality.domainPercentiles.Neuroticism;
   698→  
   699→  const score = Math.round((reactivity * 0.3 + iPosition * 0.3 + regulation * 0.2 + neuroticism * 0.2));
   700→  
   701→  let level;
   702→  if (score >= 70) level = 'high';
   703→  else if (score >= 50) level = 'moderate';
   704→  else if (score >= 35) level = 'developing';
   705→  else level = 'low';
   706→  
   707→  return { score, level };
   708→}
   709→
   710→function calculateUTurnCapacity(profile) {
   711→  // U-Turn = ability to turn attention inward during conflict
   712→  // Requires: self-awareness, pause capacity, willingness to look at self
   713→  
   714→  const selfAwareness = profile.emotionalIntelligence.subscaleNormalized.perception;
   715→  const iPosition = profile.differentiation.subscaleNormalized.iPosition;
   716→  const openness = profile.personality.domainPercentiles.Openness;
   717→  
   718→  return Math.round((selfAwareness * 0.4 + iPosition * 0.3 + openness * 0.3));
   719→}
