   726→```javascript
   727→function analyzeRegulationWindow(profile, patterns) {
   728→  const { personality, emotionalIntelligence, differentiation, attachment } = profile;
   729→  
   730→  // Calculate window of tolerance width
   731→  const windowWidth = calculateWindowWidth(profile);
   732→  
   733→  // Determine activation pattern (sympathetic response)
   734→  const activationPattern = {
   735→    triggers: [],
   736→    physicalSigns: [],
   737→    behavioralSigns: [],
   738→    cognitiveSigns: [],
   739→    typicalDuration: null
   740→  };
   741→  
   742→  // High neuroticism = more easily activated
   743→  if (personality.domainPercentiles.Neuroticism > 60) {
   744→    activationPattern.triggers.push('criticism', 'perceived rejection', 'uncertainty');
   745→    activationPattern.physicalSigns.push('racing heart', 'tension', 'restlessness');
   746→    
   747→    if (personality.facetPercentiles.N2_Anger > 60) {
   748→      activationPattern.behavioralSigns.push('sharp tone', 'defensiveness', 'attacking');
   749→    }
   750→    if (personality.facetPercentiles.N1_Anxiety > 60) {
   751→      activationPattern.behavioralSigns.push('pursuing', 'seeking reassurance', 'talking faster');
   752→    }
   753→    activationPattern.cognitiveSigns.push('black-and-white thinking', 'worst-case scenarios');
   754→  }
   755→  
   756→  // Determine shutdown pattern (dorsal vagal response)
   757→  const shutdownPattern = {
   758→    triggers: [],
   759→    physicalSigns: ['heaviness', 'numbness', 'fatigue', 'brain fog'],
   760→    behavioralSigns: [],
   761→    cognitiveSigns: ['hopelessness', 'going blank', 'what\'s the point'],
   762→    typicalDuration: null
   763→  };
   764→  
   765→  if (attachment.avoidanceScore > 4.0) {
   766→    shutdownPattern.triggers.push('emotional intensity', 'demands for closeness', 'prolonged conflict');
   767→    shutdownPattern.behavioralSigns.push('going silent', 'leaving the room', 'checking out');
   768→  }
   769→  
   770→  if (profile.conflictStyle.subscaleScores.avoiding.mean > 3.5) {
   771→    shutdownPattern.behavioralSigns.push('topic changing', 'withdrawing', 'stonewalling');
   772→  }
   773→  
   774→  // Determine flooding markers
   775→  const floodingMarkers = generateFloodingMarkers(profile);
   776→  
   777→  // Determine regulation toolkit
   778→  const regulationToolkit = assessRegulationToolkit(profile);
   779→  
   780→  // Co-regulation pattern
   781→  const coRegulationPattern = assessCoRegulationPattern(profile);
   782→  
   783→  return {
   784→    windowWidth: windowWidth,
   785→    activationPattern: activationPattern,
   786→    shutdownPattern: shutdownPattern,
   787→    floodingMarkers: floodingMarkers,
   788→    regulationToolkit: regulationToolkit,
   789→    coRegulationPattern: coRegulationPattern,
   790→    regulationPriority: patterns.hasRegulationPriority,
   791→    relatedPatterns: patterns.patterns.filter(p => 
   792→      p.id.includes('regulation') || 
   793→      p.id.includes('reactive')
   794→    )
   795→  };
   796→}
   797→
   798→function calculateWindowWidth(profile) {
   799→  const neuroticism = profile.personality.domainPercentiles.Neuroticism;
   800→  const regulation = profile.emotionalIntelligence.subscaleNormalized.managingOwn;
   801→  const reactivity = profile.differentiation.subscaleNormalized.emotionalReactivity;
   802→  const vulnerability = profile.personality.facetPercentiles.N6_Vulnerability || 50;
   803→  
   804→  // Lower neuroticism, higher regulation, higher reactivity (reversed), lower vulnerability = wider window
   805→  const score = Math.round(
   806→    ((100 - neuroticism) * 0.3) +
   807→    (regulation * 0.25) +
   808→    (reactivity * 0.25) +
   809→    ((100 - vulnerability) * 0.2)
   810→  );
   811→  
   812→  let width, description;
   813→  if (score >= 70) {
   814→    width = 'wide';
   815→    description = 'Generally able to stay regulated under pressure. Can tolerate significant stress before leaving window.';
   816→  } else if (score >= 55) {
   817→    width = 'moderate';
   818→    description = 'Adequate window under normal circumstances. Stress and conflict can narrow it.';
   819→  } else if (score >= 40) {
   820→    width = 'narrow';
   821→    description = 'Leaves window relatively easily. Needs careful attention to regulation.';
   822→  } else {
   823→    width = 'very_narrow';
   824→    description = 'Very easily dysregulated. Regulation work is top priority.';
   825→  }
   826→  
   827→  return { score, width, description };
   828→}
   829→
   830→function generateFloodingMarkers(profile) {
   831→  const markers = {
   832→    physical: [],
   833→    cognitive: [],
   834→    behavioral: [],
   835→    recoveryTime: null
   836→  };
   837→  
   838→  // Everyone has some common flooding markers
   839→  markers.physical.push('heart rate elevated', 'difficulty breathing deeply');
   840→  markers.cognitive.push('can\'t hear partner\'s words', 'all-or-nothing thinking');
   841→  
   842→  // Personalize based on profile
