   850→  
   851→  if (profile.attachment.anxietyScore > 4.0) {
   852→    markers.behavioral.push('escalating pursuit', 'desperate attempts to resolve NOW');
   853→  }
   854→  
   855→  // Estimate recovery time based on regulation capacity
   856→  const regScore = profile.emotionalIntelligence.subscaleNormalized.managingOwn;
   857→  if (regScore >= 70) markers.recoveryTime = '10-15 minutes';
   858→  else if (regScore >= 50) markers.recoveryTime = '20-30 minutes';
   859→  else markers.recoveryTime = '30+ minutes';
   860→  
   861→  return markers;
   862→}
   863→
   864→function assessRegulationToolkit(profile) {
   865→  const toolkit = {
   866→    strengths: [],
