   889→  } else {
   890→    toolkit.gaps.push('Highly reactive - quickly swept up in emotion');
   891→    toolkit.recommendations.push('Practice pause-before-responding');
   892→  }
   893→  
   894→  return toolkit;
   895→}
   896→
   897→function assessCoRegulationPattern(profile) {
