   980→
   981→function calculateValuesCongruence(profile) {
   982→  // How well do behavioral patterns align with stated values?
   983→  
   984→  let alignmentScore = 100;
   985→  let conflicts = [];
   986→  
   987→  // Check each major values-behavior alignment
   988→  const { values, attachment, conflictStyle, differentiation } = profile;
   989→  
