  1108→  if (attachment.anxietyScore > attachment.avoidanceScore + 0.5) {
  1109→    position = 'pursuer';
  1110→    positionConfidence = 'high';
  1111→  } else if (attachment.avoidanceScore > attachment.anxietyScore + 0.5) {
