  1132→  let cycleDescription;
  1133→  if (position === 'pursuer') {
  1134→    cycleDescription = {
  1135→      yourMove: 'When you sense distance or disconnection, you move toward your partner - seeking reassurance, wanting to talk it through, pursuing resolution.',
