  1267→  });
  1268→  
  1269→  // Source 2: Developmental invitations
  1270→  lensAnalysis.valuesBecoming.developmentalInvitation.forEach(inv => {
  1271→    candidates.push({
  1272→      source: 'developmental',
  1273→      id: inv.invitation.toLowerCase().replace(/\s+/g, '_'),
  1274→      description: inv.invitation,
  1275→      interpretation: inv.description,
  1276→      discomfort: inv.discomfort,
  1277→      priority: inv.difficulty === 'high' ? 'high' : 'medium'
  1278→    });
  1279→  });
  1280→  
  1281→  // Source 3: High-gap value domains
  1282→  profile.values.highGapDomains.forEach(domain => {
  1283→    candidates.push({
  1284→      source: 'values_gap',
  1285→      id: `gap_${domain}`,
  1286→      description: `Living more fully into ${domain}`,
  1287→      interpretation: `High importance but low current accordance in ${domain}`,
  1288→      priority: 'medium'
  1289→    });
  1290→  });
  1291→  
  1292→  // Source 4: Regulation deficits (if flagged)
  1293→  if (patterns.hasRegulationPriority) {
  1294→    candidates.push({
  1295→      source: 'regulation',
  1296→      id: 'regulation_capacity',
  1297→      description: 'Building self-regulation capacity',
  1298→      interpretation: 'Multiple indicators suggest regulation is a foundational growth area',
  1299→      priority: 'high'
  1300→    });
  1301→  }
  1302→  
  1303→  // Source 5: Differentiation needs
  1304→  if (profile.differentiation.totalNormalized < 45) {
  1305→    candidates.push({
  1306→      source: 'differentiation',
  1307→      id: 'differentiation_self',
  1308→      description: 'Developing a clearer, more stable sense of self',
  1309→      interpretation: 'Building differentiation will support all other relationship work',
  1310→      priority: 'high'
  1311→    });
  1312→  }
  1313→  
  1314→  // Deduplicate and prioritize
  1315→  const uniqueCandidates = deduplicateGrowthEdges(candidates);
  1316→  const prioritized = prioritizeGrowthEdges(uniqueCandidates, profile, patterns);
  1317→  
  1318→  // Select top 2-3
  1319→  const selected = prioritized.slice(0, 3);
  1320→  
  1321→  // Generate full growth edge objects
  1322→  return selected.map(edge => generateFullGrowthEdge(edge, profile, patterns, lensAnalysis));
  1323→}
