  1982→# 11. Quality Assurance Rules
  1983→
  1984→## Validation Rules
  1985→
  1986→```javascript
  1987→function validatePortrait(portrait) {
  1988→  const errors = [];
  1989→  const warnings = [];
  1990→  
  1991→  // Rule 1: Must have at least 2 growth edges
  1992→  if (portrait.growthEdges.length < 2) {
  1993→    errors.push('Insufficient growth edges identified');
  1994→  }
  1995→  
  1996→  // Rule 2: Narrative must be present
  1997→  if (!portrait.narrative.openingParagraph) {
  1998→    errors.push('Missing narrative synthesis');
  1999→  }
  2000→  
  2001→  // Rule 3: Anchor points must be populated
  2002→  if (portrait.anchorPoints.whenActivated.whatToRemember.length < 2) {
  2003→    warnings.push('Sparse activation anchors');
  2004→  }
  2005→  
  2006→  // Rule 4: Partner guide must be actionable
  2007→  if (portrait.partnerGuide.whenImActivated.whatHelps.length < 3) {
  2008→    warnings.push('Partner guide may be insufficiently specific');
  2009→  }
  2010→  
  2011→  // Rule 5: Growth edge practices must be concrete
  2012→  portrait.growthEdges.forEach(edge => {
  2013→    if (edge.practice.daily.length < 20) {
  2014→      warnings.push(`Growth edge "${edge.id}" has vague daily practice`);
  2015→    }
  2016→  });
  2017→  
  2018→  // Rule 6: Consistency check - attachment should align with cycle position
  2019→  const attachment = portrait.snapshot.attachment.style;
  2020→  const position = portrait.negativeCycle.position;
  2021→  if (attachment === 'anxious-preoccupied' && position === 'withdrawer') {
  2022→    warnings.push('Unusual: anxious attachment with withdrawer position - verify');
  2023→  }
  2024→  
  2025→  return { valid: errors.length === 0, errors, warnings };
  2026→}
  2027→```
  2028→
  2029→## Compassion Guidelines
  2030→
  2031→The portrait must:
  2032→
  2033→1. **Describe patterns as protective, not pathological**
  2034→   - "Your withdrawing pattern developed to protect you from overwhelm"
  2035→   - NOT "You have an avoidant pattern that damages relationships"
  2036→
  2037→2. **Honor the function before naming the cost**
  2038→   - First: What this pattern was trying to do
  2039→   - Then: What it costs now
  2040→
  2041→3. **Frame growth as expansion, not fixing**
  2042→   - "Expanding your repertoire to include..."
  2043→   - NOT "Fixing your tendency to..."
  2044→
  2045→4. **Use second person for connection**
  2046→   - "You tend to..." not "This person tends to..."
  2047→
  2048→5. **Include strength recognition**
  2049→   - Every lens analysis should note what's working, not just what's challenging
  2050→
  2051→## Readability Guidelines
  2052→
  2053→1. **Avoid jargon without explanation**
  2054→   - If using "differentiation," explain it
  2055→   - If using "parts," introduce the concept
  2056→
  2057→2. **Use concrete examples**
  2058→   - Not just "You avoid conflict"
  2059→   - But "When something bothers you, you might assess it as 'not worth mentioning' and swallow it"
  2060→
  2061→3. **Keep anchor phrases memorable**
  2062→   - Short enough to recall in the moment
  2063→   - Personally meaningful based on profile
