```typescript
// Assessment type enum -- all 6 assessments
export type AssessmentType = 
  | 'ecr-r' 
  | 'ipip-neo-120' 
  | 'values' 
  | 'sseit' 
  | 'dutch' 
  | 'dsi-r';

// Question input types that the generic screen must support
export type QuestionInputType = 'likert' | 'text' | 'choice' | 'ranking';

// A single Likert label option
export interface LikertOption {
  value: number;
  label: string;
}

// A single choice option (for Values scenarios)
export interface ChoiceOption {
  key: string;       // 'A', 'B', 'C', 'D'
  text: string;
  coding: string;    // e.g., 'honesty_high', 'avoidance'
}

// Generic question definition
export interface GenericQuestion {
  id: number;            // 1-indexed
  text: string;
  inputType: QuestionInputType;
  subscale?: string;     // Which subscale this belongs to
  reverseScored?: boolean;
  // For text questions:
  charLimit?: number;
  placeholder?: string;
  // For choice questions:
  choices?: ChoiceOption[];
  // For ranking questions:
  rankingItems?: { id: string; label: string }[];
  rankCount?: number;    // How many to select (e.g., 5 for Values top-5)
}

// Section definition for long assessments
export interface AssessmentSection {
  id: string;
  title: string;
  description?: string;
  questionRange: [number, number];  // [startIndex, endIndex] inclusive, 0-based
}

// The master config for an assessment
export interface AssessmentConfig {
  type: AssessmentType;
  name: string;          // Display name
  shortName: string;     // For cards/badges
  description: string;   // One-line description
  instructions: string;  // Pre-assessment instructions text
  estimatedMinutes: number;
  totalQuestions: number;
  questions: GenericQuestion[];
  likertScale?: LikertOption[];  // Default Likert scale for this assessment
  sections?: AssessmentSection[];  // For section breaks
  scoringFn: (responses: Record<string, any>) => any;  // Returns typed scores
  progressKey: string;   // AsyncStorage key for in-progress state
}

// Unified Supabase table row shape
export interface AssessmentRecord {
  id: string;
  user_id: string;
  type: AssessmentType;
  responses: Record<string, any>;  // JSONB -- raw responses
  scores: Record<string, any>;     // JSONB -- computed scores
  completed_at: string;
  created_at: string;
}

// Per-assessment score types (keep ECRRScores, add others)
export interface ECRRScores { /* existing */ }
export interface DUTCHScores {
  subscaleScores: Record<string, { sum: number; mean: number }>;
  primaryStyle: string;
  secondaryStyle: string;
}
export interface SSEITScores {
  totalScore: number;
  totalMean: number;
  totalNormalized: number;
  subscaleScores: Record<string, { sum: number; mean: number; itemCount: number }>;
  subscaleNormalized: Record<string, number>;
}
export interface DSIRScores {
  totalMean: number;
  totalNormalized: number;
  subscaleScores: Record<string, { sum: number; mean: number; itemCount: number }>;
  subscaleNormalized: Record<string, number>;
}
export interface IPIPScores {
  domainScores: Record<string, { sum: number; mean: number }>;
  domainPercentiles: Record<string, number>;
  facetScores: Record<string, { sum: number; mean: number }>;
  facetPercentiles: Record<string, number>;
}
export interface ValuesScores {
  domainScores: Record<string, { importance: number; accordance: number; gap: number }>;
  top5Values: string[];
  qualitativeResponses: { partnerIdentity: string; nonNegotiables: string; aspirationalVision: string };
  actionResponses: Record<string, string>;
  avoidanceTendency: number;
  balancedTendency: number;
  highGapDomains: string[];
}
```

**Rationale**: The `AssessmentConfig` is the central abstraction. Each assessment provides one. The generic screens consume configs. The `scoringFn` lives on the config so the assessment screen does not need to import specific scoring functions.

