/**
 * Shared types for the Couples App.
 * Designed to scale: v0.1 has ECR-R only,
 * v0.2+ adds Big Five, EI, DSI-R, DUTCH, Values.
 */

// ─── Assessment Types ───────────────────────────────────────

export type AttachmentStyle =
  | 'secure'
  | 'anxious-preoccupied'
  | 'dismissive-avoidant'
  | 'fearful-avoidant';

export interface ECRRScores {
  anxietyScore: number;
  avoidanceScore: number;
  attachmentStyle: AttachmentStyle;
}

export interface ECRRAssessment {
  id: number;
  user_id: string;
  responses: number[];
  anxiety_score: number;
  avoidance_score: number;
  attachment_style: AttachmentStyle;
  completed_at: string;
  created_at: string;
}

// ─── Question Types ─────────────────────────────────────────

export interface Question {
  id: number;        // 1-indexed (matches spec)
  text: string;
  subscale: 'anxiety' | 'avoidance';
  reverseScored: boolean;
}

// ─── Future Assessment Types (v0.2+) ────────────────────────
// These are placeholders — will be fleshed out when we add
// Big Five, EI, DSI-R, DUTCH, and Values assessments.

export type AssessmentType = 'ecr-r'; // Add more in v0.2+

