/**
 * Shared types for the Couples App.
 * Supports all 6 assessment instruments.
 */

// ─── Assessment Type Enum ─────────────────────────────────

export type AssessmentType =
  | 'ecr-r'
  | 'ipip-neo-120'
  | 'values'
  | 'sseit'
  | 'dutch'
  | 'dsi-r';

// ─── Question Input Types ─────────────────────────────────

export type QuestionInputType = 'likert' | 'text' | 'choice' | 'ranking';

export interface LikertOption {
  value: number;
  label: string;
}

export interface ChoiceOption {
  key: string;       // 'A', 'B', 'C', 'D'
  text: string;
  coding: string;    // e.g., 'honesty_high', 'avoidance'
}

export interface RankingItem {
  id: string;
  label: string;
  description?: string;
}

export interface GenericQuestion {
  id: number;               // 1-indexed
  text: string;
  inputType: QuestionInputType;
  subscale?: string;
  reverseScored?: boolean;
  // Text questions:
  charLimit?: number;
  placeholder?: string;
  // Choice questions:
  choices?: ChoiceOption[];
  // Ranking questions:
  rankingItems?: RankingItem[];
  rankCount?: number;
}

// ─── Assessment Sections (for breaks) ─────────────────────

export interface AssessmentSection {
  id: string;
  title: string;
  description?: string;
  questionRange: [number, number]; // [startIndex, endIndex] inclusive, 0-based
}

// ─── Assessment Config ────────────────────────────────────

export interface AssessmentConfig {
  type: AssessmentType;
  name: string;
  shortName: string;
  description: string;
  instructions: string;
  estimatedMinutes: number;
  totalQuestions: number;
  questions: GenericQuestion[];
  likertScale?: LikertOption[];
  sections?: AssessmentSection[];
  scoringFn: (responses: (number | string | string[] | null)[]) => any;
