   250→            <View style={styles.likertSection}>
   251→              {config.likertScale.map((item) => (
   252→                <TouchableOpacity
   253→                  key={item.value}
   254→                  style={[
   255→                    styles.likertOption,
   256→                    currentAnswer === item.value && styles.likertOptionSelected,
   257→                  ]}
   258→                  onPress={() => handleSelect(item.value)}
   259→                >
   260→                  <View
   261→                    style={[
   262→                      styles.radio,
   263→                      currentAnswer === item.value && styles.radioSelected,
   264→                    ]}
   265→                  >
   266→                    {currentAnswer === item.value && <View style={styles.radioInner} />}
   267→                  </View>
   268→                  <Text
   269→                    style={[
   270→                      styles.likertLabel,
   271→                      currentAnswer === item.value && styles.likertLabelSelected,
   272→                    ]}
   273→                  >
   274→                    {item.value} — {item.label}
   275→                  </Text>
   276→                </TouchableOpacity>
   277→              ))}
   278→            </View>
   279→          )}
   280→
   281→          {question.inputType === 'text' && (
   282→            <View style={styles.textInputSection}>
   283→              <RNTextInput
   284→                style={styles.textInput}
   285→                placeholder={question.placeholder || 'Type your response...'}
   286→                placeholderTextColor={Colors.textSecondary}
   287→                value={currentAnswer || ''}
