   302→                <TouchableOpacity
   303→                  key={choice.key}
   304→                  style={[
   305→                    styles.choiceOption,
   306→                    currentAnswer === choice.key && styles.choiceOptionSelected,
   307→                  ]}
   308→                  onPress={() => handleSelect(choice.key)}
   309→                >
   310→                  <View style={styles.choiceKeyBadge}>
   311→                    <Text
   312→                      style={[
