   325→                  >
   326→                    {choice.text}
   327→                  </Text>
   328→                </TouchableOpacity>
   329→              ))}
   330→            </View>
   331→          )}
   332→
   333→          {question.inputType === 'ranking' && question.rankingItems && (
   334→            <View style={styles.rankingSection}>
   335→              <Text style={styles.rankingHint}>
   336→                Tap items in order of importance (1st, 2nd, 3rd...). Tap again to remove.
   337→              </Text>
   338→              {question.rankingItems.map((item) => {
   339→                const ranked = (currentAnswer as string[]) || [];
   340→                const position = ranked.indexOf(item.id);
   341→                const isSelected = position !== -1;
   342→                const isFull = ranked.length >= (question.rankCount || 5);
   343→                return (
   344→                  <TouchableOpacity
   345→                    key={item.id}
   346→                    style={[
   347→                      styles.rankingItem,
   348→                      isSelected && styles.rankingItemSelected,
   349→                      !isSelected && isFull && styles.rankingItemDisabled,
   350→                    ]}
   351→                    disabled={!isSelected && isFull}
   352→                    onPress={() => {
   353→                      if (isSelected) {
   354→                        handleSelect(ranked.filter((id: string) => id !== item.id));
   355→                      } else {
   356→                        handleSelect([...ranked, item.id]);
   357→                      }
   358→                    }}
   359→                  >
   360→                    <View
   361→                      style={[
