   367→                        {isSelected ? position + 1 : '—'}
   368→                      </Text>
   369→                    </View>
   370→                    <View style={styles.rankingItemContent}>
   371→                      <Text style={styles.rankingItemLabel}>{item.label}</Text>
   372→                      {item.description ? (
