import React, { useCallback, useEffect, useState } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  SafeAreaView,
  ScrollView,
} from 'react-native';
import { useRouter } from 'expo-router';
import { useFocusEffect } from '@react-navigation/native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useAuth } from '@/context/AuthContext';
import { getAllAssessments, ASSESSMENT_ORDER } from '@/utils/assessments/registry';
import { supabase } from '@/services/supabase';
import { Colors, Spacing, FontSizes, ButtonSizes } from '@/constants/theme';
import type { AssessmentConfig, AssessmentType } from '@/types';

interface CardStatus {
  state: 'not_started' | 'in_progress' | 'completed';
  progressQuestion?: number;
  totalQuestions?: number;
  completedAt?: string;
}

export default function HomeScreen() {
  const { user, signOut } = useAuth();
  const router = useRouter();
  const [statuses, setStatuses] = useState<Record<string, CardStatus>>({});

  const loadStatuses = useCallback(async () => {
    if (!user) return;
    const newStatuses: Record<string, CardStatus> = {};

    // Check completed assessments from Supabase
    const { data: completed } = await supabase
      .from('assessments')
      .select('type, completed_at')
      .eq('user_id', user.id)
      .order('completed_at', { ascending: false });

    const completionMap: Record<string, string> = {};
    if (completed) {
      for (const row of completed) {
        if (!completionMap[row.type]) {
          completionMap[row.type] = row.completed_at;
        }
      }
    }

    // Check in-progress from AsyncStorage for each assessment
    const allConfigs = getAllAssessments();
    for (const config of allConfigs) {
      if (completionMap[config.type]) {
        newStatuses[config.type] = {
          state: 'completed',
          completedAt: completionMap[config.type],
        };
      } else {
        try {
          const saved = await AsyncStorage.getItem(config.progressKey);
          if (saved) {
            const data = JSON.parse(saved);
            const answered = data.responses.filter(
              (r: any) => r !== null && r !== '' && r !== undefined
            ).length;
            if (answered > 0) {
              newStatuses[config.type] = {
                state: 'in_progress',
                progressQuestion: answered,
                totalQuestions: config.totalQuestions,
              };
            } else {
              newStatuses[config.type] = { state: 'not_started' };
            }
          } else {
            newStatuses[config.type] = { state: 'not_started' };
          }
        } catch {
          newStatuses[config.type] = { state: 'not_started' };
        }
      }
    }
    setStatuses(newStatuses);
  }, [user]);

  // Reload statuses whenever the screen comes into focus
  useFocusEffect(
    useCallback(() => {
      loadStatuses();
    }, [loadStatuses])
  );

  const handleStart = async (config: AssessmentConfig) => {
    await AsyncStorage.removeItem(config.progressKey);
    router.push({ pathname: '/(app)/assessment', params: { type: config.type } });
  };

  const handleResume = (config: AssessmentConfig) => {
    router.push({ pathname: '/(app)/assessment', params: { type: config.type } });
  };

  const handleLogout = async () => {
    const allConfigs = getAllAssessments();
    for (const config of allConfigs) {
      await AsyncStorage.removeItem(config.progressKey);
    }
    await signOut();
    router.replace('/(auth)/login');
  };

  const allConfigs = getAllAssessments();

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.scrollContent}>
        <View style={styles.header}>
          <Text style={styles.greeting}>Hi, {user?.email}</Text>
          <Text style={styles.title}>Your Assessments</Text>
          <Text style={styles.subtitle}>
            Complete these to build your relationship profile
          </Text>
        </View>

        <View style={styles.cards}>
          {allConfigs.map((config) => {
            const status = statuses[config.type] || { state: 'not_started' };
            return (
              <View key={config.type} style={styles.card}>
                <View style={styles.cardHeader}>
                  <View style={styles.cardTitleRow}>
                    <Text style={styles.cardShortName}>{config.shortName}</Text>
                    <StatusBadge status={status} />
                  </View>
                  <Text style={styles.cardName}>{config.name}</Text>
                  <Text style={styles.cardDescription}>{config.description}</Text>
                  <Text style={styles.cardMeta}>
                    {config.totalQuestions} questions · ~{config.estimatedMinutes} min
                  </Text>
                </View>

                <View style={styles.cardActions}>
                  {status.state === 'not_started' && (
                    <TouchableOpacity
                      style={styles.cardButton}
                      onPress={() => handleStart(config)}
                    >
                      <Text style={styles.cardButtonText}>Start</Text>
                    </TouchableOpacity>
                  )}
                  {status.state === 'in_progress' && (
                    <>
                      <Text style={styles.progressNote}>
                        {status.progressQuestion} of {status.totalQuestions} answered
                      </Text>
                      <TouchableOpacity
                        style={styles.cardButton}
                        onPress={() => handleResume(config)}
                      >
                        <Text style={styles.cardButtonText}>Continue</Text>
                      </TouchableOpacity>
                    </>
                  )}
                  {status.state === 'completed' && (
                    <TouchableOpacity
                      style={styles.cardButtonOutline}
                      onPress={() => handleStart(config)}
                    >
                      <Text style={styles.cardButtonOutlineText}>Retake</Text>
                    </TouchableOpacity>
                  )}
                </View>
              </View>
            );
          })}
        </View>

        <TouchableOpacity style={styles.logoutButton} onPress={handleLogout}>
          <Text style={styles.logoutText}>Logout</Text>
        </TouchableOpacity>
      </ScrollView>
    </SafeAreaView>
  );
}

function StatusBadge({ status }: { status: CardStatus }) {
  if (status.state === 'completed') {
    return (
      <View style={[styles.badge, styles.badgeCompleted]}>
        <Text style={styles.badgeCompletedText}>Completed</Text>
      </View>
    );
  }
  if (status.state === 'in_progress') {
    return (
      <View style={[styles.badge, styles.badgeInProgress]}>
        <Text style={styles.badgeInProgressText}>In Progress</Text>
      </View>
    );
  }
  return null;
}

