import React from 'react';
import { View, Text, TouchableOpacity, StyleSheet, SafeAreaView } from 'react-native';
import { useLocalSearchParams, useRouter } from 'expo-router';
import { Colors, Spacing, FontSizes, ButtonSizes } from '@/constants/theme';
import ECRRResults from '@/components/results/ECRRResults';

export default function ResultsScreen() {
  const router = useRouter();
  const params = useLocalSearchParams<{ type: string; scores: string }>();
  const type = params.type || 'ecr-r';

  let scores: any;
  try {
    scores = JSON.parse(params.scores);
  } catch {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.center}>
          <Text style={styles.errorText}>Could not load results.</Text>
          <TouchableOpacity
            style={styles.button}
            onPress={() => router.replace('/(app)/home')}
          >
            <Text style={styles.buttonText}>Back to Home</Text>
          </TouchableOpacity>
        </View>
      </SafeAreaView>
    );
  }

  switch (type) {
    case 'ecr-r':
      return <ECRRResults scores={scores} />;
    // Future assessment results will be added here:
    // case 'dutch':
    //   return <DUTCHResults scores={scores} />;
    default:
      return (
        <SafeAreaView style={styles.container}>
          <View style={styles.center}>
            <Text style={styles.errorText}>
              Results view not yet available for: {type}
            </Text>
            <TouchableOpacity
              style={styles.button}
              onPress={() => router.replace('/(app)/home')}
            >
              <Text style={styles.buttonText}>Back to Home</Text>
            </TouchableOpacity>
          </View>
        </SafeAreaView>
      );
  }
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: Colors.background },
  center: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    padding: Spacing.xl,
    gap: Spacing.lg,
  },
  errorText: {
    fontSize: FontSizes.body,
    color: Colors.textSecondary,
    textAlign: 'center',
  },
  button: {
    backgroundColor: Colors.primary,
    height: ButtonSizes.large,
    borderRadius: 8,
    justifyContent: 'center',
    alignItems: 'center',
    paddingHorizontal: Spacing.xl,
  },
  buttonText: {
    color: Colors.white,
    fontSize: FontSizes.body,
    fontWeight: '600',
  },
});

